export type Post = {
  id: number;
  title: string;
  content: string;
  createdAt: Date;
};

let posts: Post[] = [
  {
    id: 1,
    title: 'Hello World',
    content: 'This is the first post.',
    createdAt: new Date('2026-01-01'),
  },
];

export function getPosts(): Promise<Post[]> {
  return Promise.resolve([...posts]);
}

export async function addPost(title: string, content: string): Promise<Post> {
  const post: Post = {
    id: posts.length > 0 ? Math.max(...posts.map((p) => p.id)) + 1 : 1,
    title,
    content,
    createdAt: new Date(),
  };
  posts = [...posts, post];
  return post;
}

'use server';

import { revalidateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  await addPost(title, content);

  // Invalidate the "posts" cache tag so the next request re-fetches fresh data.
  revalidateTag('posts');

  // Redirect to the home page, forcing a full server-side re-render
  // that will execute getCachedPosts() fresh (cache was just invalidated).
  redirect('/');
}

'use client';

import { createPost } from '@/app/actions';

export function PostForm() {
  return (
    <form action={createPost}>
      <div>
        <label htmlFor="title">Title</label>
        <input type="text" id="title" name="title" required />
      </div>
      <div>
        <label htmlFor="content">Content</label>
        <textarea id="content" name="content" required />
      </div>
      <button type="submit">Create Post</button>
    </form>
  );
}

import { unstable_cache } from 'next/cache';
import { getPosts } from '@/app/lib/posts';
import { PostForm } from '@/app/post-form';

const getCachedPosts = unstable_cache(
  async () => getPosts(),
  ['posts-list'],
  { tags: ['posts'] },
);

export default async function Home() {
  const posts = await getCachedPosts();

  return (
    <main>
      <h1>Posts</h1>

      <PostForm />

      <h2>All Posts</h2>

      {posts.length === 0 ? (
        <p>No posts yet.</p>
      ) : (
        <ul>
          {posts.map((post) => (
            <li key={post.id}>
              <h3>{post.title}</h3>
              <p>{post.content}</p>
              <small>{post.createdAt.toLocaleDateString()}</small>
            </li>
          ))}
        </ul>
      )}
    </main>
  );
}

