'use server';

import { updateTag } from 'next/cache';
import { redirect } from 'next/navigation';
import { addPost } from '@/app/lib/posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string;
  const content = formData.get('content') as string;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  await addPost(title, content);

  // Invalidate the "posts" cache tag with immediate expiration and
  // read-your-own-writes semantics — guarantees no stale content is served
  // on the next request because the path is marked as fully revalidated
  // and the next fetch with this tag must wait for fresh data.
  updateTag('posts');

  // Redirect to the home page, forcing a full server-side re-render
  // that executes getCachedPosts() with a fresh cache (invalidated above).
  redirect('/');
}

